import { ModelType } from './types';

export const DEFAULT_MODEL = ModelType.Flash;

export const SYSTEM_INSTRUCTION = `You are a helpful, clever, and highly capable AI assistant powered by Google's Gemini models. 
You can analyze images, write code, and answer complex questions.
When writing code, always use markdown code blocks with the language specified.
