import { GoogleGenAI, GenerateContentResponse, Chat } from "@google/genai";
import { Message, MessageRole, ModelType, Attachment } from "../types";
import { SYSTEM_INSTRUCTION } from "../constants";

// Ensure API Key is available
const API_KEY = process.env.API_KEY || '';

class GeminiService {
  private ai: GoogleGenAI;
  private chatSession: Chat | null = null;
  private currentModel: string = ModelType.Flash;

  constructor() {
    if (!API_KEY) {
      console.warn("API Key is missing. Please set process.env.API_KEY.");
    }
    this.ai = new GoogleGenAI({ apiKey: API_KEY });
  }

  public async startChat(model: string = ModelType.Flash) {
    this.currentModel = model;
    this.chatSession = this.ai.chats.create({
      model: model,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
      },
    });
  }

  /**
   * Helper to convert file to base64
   */
  private async fileToBase64(file: File): Promise<string> {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        // Remove data url prefix (e.g. "data:image/png;base64,")
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = error => reject(error);
    });
  }

  /**
   * Sends a message with optional attachments.
   * If attachments are present, it uses a single-turn generateContent (for simplicity in this demo structure),
   * or a chat message if the model supports it.
   */
  public async *streamMessage(
    text: string, 
    attachments: Attachment[] = [],
    history: Message[] // We might use this if we need to rebuild context manually, but SDK handles chat state
  ): AsyncGenerator<string, void, unknown> {

    if (!this.chatSession) {
      await this.startChat(this.currentModel);
    }

    try {
      let stream;

      // Logic: If there are attachments, we construct a multipart message.
      if (attachments.length > 0) {
        // Prepare parts
        const parts: any[] = [];

        for (const att of attachments) {
          const base64Data = await this.fileToBase64(att.file);
          parts.push({
            inlineData: {
              mimeType: att.file.type,
              data: base64Data
            }
          });
        }

        if (text) {
          parts.push({ text });
        }

        // For multimodal chat, we use the chat session. 
        // Note: Gemini 1.5/2.5/3 series supports multimodal history in chat.
        stream = await this.chatSession!.sendMessageStream({
          message: {
            content: {
              parts: parts
            }
          }
        });

      } else {
        // Text only
        stream = await this.chatSession!.sendMessageStream({
          message: text
        });
      }

      for await (const chunk of stream) {
        const c = chunk as GenerateContentResponse;
        if (c.text) {
          yield c.text;
        }
      }

    } catch (error) {
      console.error("Gemini API Error:", error);
      yield "\n\n*Error: Unable to process request. Please check your connection or API key.*";
    }
  }

  /**
   * Specialized Image Generation function
   */
  public async generateImage(prompt: string): Promise<string | null> {
    try {
      // Using gemini-2.5-flash-image for generation as per guide
      const response = await this.ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
            parts: [{ text: prompt }]
        },
        config: {
            imageConfig: {
                aspectRatio: "1:1",
                imageSize: "1K"
            }
        }
      });

      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
      return null;
    } catch (e) {
      console.error("Image Gen Error", e);
      throw e;
    }
  }
}

