import React, { useState, useRef, useEffect } from 'react';
import { Send, Paperclip, X, Image as ImageIcon, Mic } from 'lucide-react';
import { Attachment } from '../types';

interface InputAreaProps {
  onSend: (text: string, attachments: Attachment[]) => void;
  isLoading: boolean;
}

export const InputArea: React.FC<InputAreaProps> = ({ onSend, isLoading }) => {
  const [text, setText] = useState('');
  const [attachments, setAttachments] = useState<Attachment[]>([]);
  const textareaRef = useRef<HTMLTextAreaElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Auto-resize textarea
  useEffect(() => {
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${Math.min(textareaRef.current.scrollHeight, 200)}px`;
    }
  }, [text]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleSend = () => {
    if ((!text.trim() && attachments.length === 0) || isLoading) return;
    onSend(text, attachments);
    setText('');
    setAttachments([]);
    if (textareaRef.current) textareaRef.current.style.height = 'auto';
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      const newAttachments: Attachment[] = Array.from(e.target.files).map((file: File) => ({
        file,
        previewUrl: URL.createObjectURL(file),
        type: file.type.startsWith('image/') ? 'image' : 'unknown'
      }));
      setAttachments(prev => [...prev, ...newAttachments]);
    }
    // Reset input
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const removeAttachment = (index: number) => {
    setAttachments(prev => prev.filter((_, i) => i !== index));
  };

  return (
    <div className="w-full max-w-4xl mx-auto px-4 pb-6 pt-2">
      <div className="relative bg-slate-800/80 backdrop-blur-md border border-slate-700 rounded-3xl shadow-2xl transition-all focus-within:ring-2 focus-within:ring-gemini-500/50 focus-within:border-gemini-500/50">

        {/* Attachment Previews */}
        {attachments.length > 0 && (
          <div className="flex px-4 pt-4 gap-3 overflow-x-auto scrollbar-hide">
            {attachments.map((att, idx) => (
              <div key={idx} className="relative group shrink-0">
                <img src={att.previewUrl} alt="preview" className="h-16 w-16 object-cover rounded-lg border border-slate-600" />
                <button 
                  onClick={() => removeAttachment(idx)}
                  className="absolute -top-1 -right-1 bg-red-500 text-white rounded-full p-0.5 shadow-md hover:bg-red-600 transition-colors"
                >
                  <X size={12} />
                </button>
              </div>
            ))}
          </div>
        )}

        {/* Input Area */}
        <div className="flex items-end p-3 gap-2">

          <input 
            type="file" 
            ref={fileInputRef}
            onChange={handleFileChange}
            multiple
            accept="image/*"
            className="hidden" 
          />

          <button 
            onClick={() => fileInputRef.current?.click()}
            className="p-2 text-slate-400 hover:text-gemini-300 hover:bg-slate-700/50 rounded-full transition-colors tooltip-trigger"
            title="Attach images"
          >
            <Paperclip size={20} />
          </button>

          <textarea
            ref={textareaRef}
            value={text}
            onChange={(e) => setText(e.target.value)}
            onKeyDown={handleKeyDown}
            placeholder="Message Gemini..."
            className="flex-1 bg-transparent text-slate-100 placeholder-slate-500 outline-none resize-none py-2 px-1 max-h-[200px] overflow-y-auto"
            rows={1}
          />

          <div className="flex items-center gap-1">
             {/* Mic button placeholder (for aesthetics, functionality not fully impl in this snippet) */}
            <button className="p-2 text-slate-400 hover:text-slate-200 hover:bg-slate-700/50 rounded-full transition-colors hidden sm:block">
               <Mic size={20} />
            </button>

            <button 
              onClick={handleSend}
              disabled={(!text.trim() && attachments.length === 0) || isLoading}
              className={`p-2 rounded-xl transition-all duration-200 
                ${(!text.trim() && attachments.length === 0) || isLoading 
                  ? 'bg-slate-700 text-slate-500 cursor-not-allowed' 
                  : 'bg-white text-gemini-900 hover:bg-gemini-50 shadow-lg shadow-white/10'}`}
            >
              <Send size={20} className={isLoading ? 'opacity-0' : 'opacity-100'} />
              {isLoading && (
                <div className="absolute inset-0 flex items-center justify-center">
                  <div className="w-5 h-5 border-2 border-gemini-900 border-t-transparent rounded-full animate-spin" />
                </div>
              )}
            </button>
          </div>
        </div>
      </div>
      <div className="text-center text-xs text-slate-500 mt-2">
        Gemini may display inaccurate info, including about people, so double-check its responses.
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Sidebar } from './components/Sidebar';
import { MessageBubble } from './components/MessageBubble';
import { InputArea } from './components/InputArea';
import { Message, MessageRole, ChatSession, Attachment } from './types';
import { geminiService } from './services/geminiService';
import { PanelLeftOpen, Zap } from 'lucide-react';
import { SUGGESTIONS } from './constants';

const App: React.FC = () => {
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [currentSessionId, setCurrentSessionId] = useState<string>('1');
  const [sessions, setSessions] = useState<ChatSession[]>([
    { id: '1', title: 'New Chat', messages: [], createdAt: new Date() }
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const currentSession = sessions.find(s => s.id === currentSessionId) || sessions[0];

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  };

  useEffect(() => {
    scrollToBottom();
  }, [currentSession.messages]);

  const toggleSidebar = () => setSidebarOpen(!sidebarOpen);

  const startNewChat = () => {
    const newSession: ChatSession = {
      id: Date.now().toString(),
      title: 'New Chat',
      messages: [],
      createdAt: new Date()
    };
    setSessions(prev => [newSession, ...prev]);
    setCurrentSessionId(newSession.id);
    geminiService.startChat(); // Reset service chat state
  };

  const updateSessionMessages = (sessionId: string, newMessages: Message[]) => {
    setSessions(prev => prev.map(s => {
      if (s.id === sessionId) {
        // Update title based on first user message if it's "New Chat"
        let title = s.title;
        if (title === 'New Chat' && newMessages.length > 0) {
           const firstUserMsg = newMessages.find(m => m.role === MessageRole.User);
           if (firstUserMsg) {
             title = firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
           }
        }
        return { ...s, title, messages: newMessages };
      }
      return s;
    }));
  };

  const handleSend = async (text: string, attachments: Attachment[]) => {
    if (!text.trim() && attachments.length === 0) return;

    // 1. Add User Message
    const userMessage: Message = {
      id: Date.now().toString(),
      role: MessageRole.User,
      text: text,
      timestamp: new Date(),
      attachments: attachments
    };

    const updatedMessages = [...currentSession.messages, userMessage];
    updateSessionMessages(currentSessionId, updatedMessages);
    setIsLoading(true);

    try {
      // 2. Check if it's an image generation request (simple heuristic)
      const isImageGen = text.toLowerCase().startsWith('generate image') || 
                         text.toLowerCase().startsWith('create an image') ||
                         text.toLowerCase().includes('draw a');

      if (isImageGen && attachments.length === 0) {
        const imageUrl = await geminiService.generateImage(text);

        const modelMessage: Message = {
          id: (Date.now() + 1).toString(),
          role: MessageRole.Model,
          text: imageUrl ? "Here is the image you requested:" : "Sorry, I couldn't generate that image.",
          timestamp: new Date(),
          attachments: imageUrl ? [{ file: new File([], 'gen.png'), previewUrl: imageUrl, type: 'image' }] : []
        };
        updateSessionMessages(currentSessionId, [...updatedMessages, modelMessage]);
      } else {
        // 3. Normal Text/Multimodal Chat Streaming
        const modelMessageId = (Date.now() + 1).toString();
        let fullResponse = "";

        // Create placeholder message
        const placeholderMessage: Message = {
          id: modelMessageId,
          role: MessageRole.Model,
          text: "",
          timestamp: new Date(),
          isThinking: true
        };

        updateSessionMessages(currentSessionId, [...updatedMessages, placeholderMessage]);

        const stream = geminiService.streamMessage(text, attachments, updatedMessages);

        for await (const chunk of stream) {
            fullResponse += chunk;
            // Update the message in place
            updateSessionMessages(currentSessionId, [...updatedMessages, {
                ...placeholderMessage,
                text: fullResponse,
                isThinking: false
            }]);
        }
      }

    } catch (error) {
      console.error(error);
      const errorMessage: Message = {
        id: Date.now().toString(),
        role: MessageRole.System,
        text: "Something went wrong. Please try again.",
        timestamp: new Date()
      };
      updateSessionMessages(currentSessionId, [...updatedMessages, errorMessage]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="flex h-screen w-full overflow-hidden bg-dark-bg text-slate-100 font-sans selection:bg-gemini-500/30">

      <Sidebar 
        isOpen={sidebarOpen} 
        toggleSidebar={toggleSidebar}
        startNewChat={startNewChat}
        sessions={sessions}
        currentSessionId={currentSessionId}
        onSelectSession={setCurrentSessionId}
      />

      {/* Main Content */}
      <div className={`flex-1 flex flex-col h-full transition-all duration-300 relative ${sidebarOpen ? 'lg:ml-64' : 'ml-0'}`}>

        {/* Top Navigation Bar */}
        <header className="h-16 flex items-center justify-between px-4 lg:px-8 border-b border-dark-border bg-dark-bg/80 backdrop-blur z-10 sticky top-0">
          <div className="flex items-center gap-3">
            {!sidebarOpen && (
              <button onClick={toggleSidebar} className="text-slate-400 hover:text-white p-1 rounded-md hover:bg-slate-800">
                <PanelLeftOpen size={20} />
              </button>
            )}
            <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-slate-800 border border-slate-700 text-sm font-medium hover:bg-slate-700 cursor-pointer transition-colors">
              <Zap size={14} className="text-gemini-400 fill-gemini-400" />
              <span>Gemini 3.0 Flash</span>
            </div>
          </div>
          <div className="flex items-center gap-4">
             {/* Add extra header controls here if needed */}
          </div>
        </header>

        {/* Chat Area */}
        <main className="flex-1 overflow-y-auto w-full relative">
          <div className="max-w-4xl mx-auto px-4 lg:px-8 py-8 min-h-full flex flex-col">

            {currentSession.messages.length === 0 ? (
              <div className="flex-1 flex flex-col items-center justify-center space-y-8 mt-[-10vh]">
                <div className="w-20 h-20 rounded-2xl bg-gradient-to-br from-gemini-400 to-purple-600 flex items-center justify-center shadow-2xl shadow-gemini-500/30 animate-pulse-slow">
                    <span className="text-4xl text-white">✦</span>
                </div>
                <h1 className="text-4xl font-semibold text-transparent bg-clip-text bg-gradient-to-r from-slate-100 to-slate-400 text-center">
                  Hello, Human.
                </h1>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3 w-full max-w-2xl">
                  {SUGGESTIONS.map((suggestion, idx) => (
                    <button 
                      key={idx}
                      onClick={() => handleSend(suggestion, [])}
                      className="p-4 rounded-xl border border-slate-700 bg-slate-800/30 hover:bg-slate-800 hover:border-gemini-500/50 transition-all text-left text-sm text-slate-300 group"
                    >
                      <span className="group-hover:text-gemini-300 transition-colors">{suggestion}</span>
                    </button>
                  ))}
                </div>
              </div>
            ) : (
              <div className="space-y-6 pb-4">
                {currentSession.messages.map((msg) => (
                  <MessageBubble key={msg.id} message={msg} />
                ))}
                {/* Invisible element to scroll to */}
                <div ref={scrollRef} />
              </div>
            )}
          </div>
        </main>

        {/* Input Footer */}
        <footer className="w-full bg-gradient-to-t from-dark-bg via-dark-bg to-transparent pb-4 pt-10">
           <InputArea onSend={handleSend} isLoading={isLoading} />
        </footer>
      </div>
    </div>
  );
};

export default App;
